const text = ($input.item.json.message?.text || '').trim();

// Check business prefix
const forceBusiness = text.toLowerCase().startsWith('b:');
const cleanText = forceBusiness ? text.substring(2).trim() : text;

// Extract payment method if first word matches known methods
const methodWords = ['cash','upi','card','neft','rtgs','cheque','gpay','paytm','phonepe'];
const words = cleanText.split(/\s+/);
let paymentMethod = 'UPI';
let remaining = cleanText;
if (methodWords.includes(words[0].toLowerCase())) {
  const methodMap = { cash: 'Cash', upi: 'UPI', card: 'Card', neft: 'NEFT', rtgs: 'RTGS', cheque: 'Cheque', gpay: 'UPI', paytm: 'UPI', phonepe: 'UPI' };
  paymentMethod = methodMap[words[0].toLowerCase()] || 'UPI';
  remaining = words.slice(1).join(' ');
}

// Extract amount — first number found in remaining
const amountMatch = remaining.match(/([\d,]+(?:\.\d{2})?)/);
const amount = amountMatch ? parseFloat(amountMatch[1].replace(/,/g, '')) : 0;

// Everything after the amount is merchant + notes
const afterAmount = remaining.replace(amountMatch?.[0] || '', '').trim();
const afterWords = afterAmount.split(/\s+/);
const merchant = afterWords.slice(0, 2).join(' ') || 'Unknown';
const notes = afterWords.slice(2).join(' ') || '';

return [{ json: {
  amount,
  date: new Date().toISOString().split('T')[0],
  merchant,
  paymentMethod,
  userNote: forceBusiness ? 'b:' + notes : notes,
  forceBusiness,
  rawText: text,
  driveLink: '',
  ocrSuccess: true
} }];

const input = $input.item.json;
const text = (input.rawText + ' ' + input.merchant).toLowerCase();
const userNote = (input.userNote || '').toLowerCase();
const forceBusiness = input.forceBusiness;

const rules = [
  { category: 'Food & Drink', type: 'Personal', keywords: ['zomato','swiggy','starbucks','cafe','restaurant','biryani','pizza','food','eat','dominos','mcdonald','kfc','burger','dine'] },
  { category: 'Transport', type: 'Personal', keywords: ['uber','ola','rapido','petrol','fuel','toll','parking','auto','cab','rickshaw','metro'] },
  { category: 'Shopping', type: 'Personal', keywords: ['amazon','flipkart','myntra','mall','store','shop','meesho','retail'] },
  { category: 'Bills & Utilities', type: 'Personal', keywords: ['electricity','water','broadband','jio','airtel','bsnl','recharge','bill','internet','wifi'] },
  { category: 'Medical', type: 'Personal', keywords: ['pharmacy','hospital','doctor','clinic','medicine','apollo','medplus','health'] },
  { category: 'Business - Software', type: 'Business', keywords: ['aws','notion','slack','zoom','adobe','subscription','saas','github','figma'] },
  { category: 'Business - Travel', type: 'Business', keywords: ['flight','hotel','train ticket','business travel','airport'] },
  { category: 'Business - Meals', type: 'Business', keywords: ['client lunch','vendor meeting','team lunch','business meal'] },
  { category: 'Vendor Payment', type: 'Business', keywords: ['vendor','supplier','contractor','invoice','advance'] },
  { category: 'Cash', type: 'Personal', keywords: ['atm','cash withdrawal'] },
];

let category = 'Other';
let type = 'Personal';

for (const rule of rules) {
  if (rule.keywords.some(kw => text.includes(kw) || userNote.includes(kw))) {
    category = rule.category;
    type = rule.type;
    break;
  }
}

if (forceBusiness) type = 'Business';

return [{ json: { ...input, category, type } }];
